using System;

class Program
{
    const double TaxRate = 0.08;
    const string CurrencySymbol = "$";

    static void Main()
    {
        double price = 49.99;
        double tax = price * TaxRate;
        double total = price + tax;

        Console.WriteLine($"Price: {CurrencySymbol}{price}");
        Console.WriteLine($"Tax: {CurrencySymbol}{tax:F2}");
        Console.WriteLine($"Total: {CurrencySymbol}{total:F2}");
    }
}
